import React, { useState } from 'react';
import Dashboard from './Dashboard';
import { uploadDNA } from './api';

function App() {
    const [analysisData, setAnalysisData] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);

    const handleFileUpload = async (event) => {
        const file = event.target.files[0];
        if (!file) return;

        setIsLoading(true);
        setError(null);

        try {
            const response = await uploadDNA(file);
            if (response.status === "success") {
                setAnalysisData(response.data);
            } else {
                setError("Analysis failed. Please check the file format.");
            }
        } catch (err) {
            setError("Cannot connect to backend. Make sure main.py is running!");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div style={styles.container}>
            <header style={styles.header}>
                <h1 style={styles.title}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <p style={styles.subtitle}>Precision nutrition based on your genetic markers.</p>
            </header>

            <main>
                {!analysisData ? (
                    <div style={styles.uploadCard}>
                        <h3>Upload DNA Data</h3>
                        <p>Select your raw genomic .txt file to begin analysis.</p>
                        <div style={{marginTop: '30px'}}>
                            <input type="file" onChange={handleFileUpload} id="dna-file" hidden accept=".txt" />
                            <label htmlFor="dna-file" style={isLoading ? styles.btnDisabled : styles.uploadBtn}>
                                {isLoading ? "Analyzing Genetics..." : "Select .txt File"}
                            </label>
                        </div>
                        {error && <p style={{color: 'red', marginTop: '20px'}}>{error}</p>}
                    </div>
                ) : (
                    <Dashboard data={analysisData} onReset={() => setAnalysisData(null)} />
                )}
            </main>
        </div>
    );
}

const styles = {
    container: { maxWidth: '1000px', margin: '0 auto', padding: '50px 20px', fontFamily: 'sans-serif' },
    header: { textAlign: 'center', marginBottom: '50px' },
    title: { fontSize: '2.5rem', fontWeight: 'bold', margin: 0 },
    subtitle: { color: '#666' },
    uploadCard: { background: '#f9f9f9', padding: '60px', borderRadius: '20px', textAlign: 'center', border: '1px solid #eee' },
    uploadBtn: { background: '#1a202c', color: '#fff', padding: '12px 30px', borderRadius: '8px', cursor: 'pointer' },
    btnDisabled: { background: '#ccc', color: '#fff', padding: '12px 30px', borderRadius: '8px', cursor: 'not-allowed' }
};

export default App;
